import { FORMS_EMAIL_TEMPLATE_ENTITY_TYPE, FORMS_EMAIL_TEMPLATE_FOLDER_ENTITY_TYPE, FORMS_EMAIL_TEMPLATE_ROOT_ENTITY_TYPE } from '../entity.js';
import type { FormsEmailTemplateTreeItemModel } from './types.js';
import { UmbServerFilePathUniqueSerializer } from '@umbraco-cms/backoffice/server-file-system';
import type {
	UmbTreeAncestorsOfRequestArgs,
	UmbTreeChildrenOfRequestArgs,
	UmbTreeRootItemsRequestArgs,
} from '@umbraco-cms/backoffice/tree';
import { UmbTreeServerDataSourceBase } from '@umbraco-cms/backoffice/tree';
import type { FileSystemTreeItemPresentationModel } from '@umbraco-cms/backoffice/external/backend-api';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import { EmailTemplateService } from '@umbraco-forms/generated';

export class FormsEmailTemplateTreeServerDataSource extends UmbTreeServerDataSourceBase<
	FileSystemTreeItemPresentationModel,
	FormsEmailTemplateTreeItemModel
> {
	constructor(host: UmbControllerHost) {
		super(host, {
			getRootItems,
			getChildrenOf,
			getAncestorsOf,
			mapper,
		});
	}
}

const getRootItems = (args: UmbTreeRootItemsRequestArgs) =>
	// eslint-disable-next-line local-rules/no-direct-api-import
	EmailTemplateService.getTreeEmailTemplateRoot();

const getChildrenOf = (args: UmbTreeChildrenOfRequestArgs) => {
	const parentPath = new UmbServerFilePathUniqueSerializer().toServerPath(args.parent.unique);

	if (parentPath === null) {
		return getRootItems(args);
	} else {
		// eslint-disable-next-line local-rules/no-direct-api-import
		return EmailTemplateService.getTreeEmailTemplateChildrenByParentPath({
			parentPath,
		});
	}
};

const getAncestorsOf = (args: UmbTreeAncestorsOfRequestArgs) => {
	throw new Error("Ancestors is not available.");
};

const mapper = (item: FileSystemTreeItemPresentationModel): FormsEmailTemplateTreeItemModel => {
	const serializer = new UmbServerFilePathUniqueSerializer();

	return {
		unique: serializer.toUnique(item.path),
		parent: {
			unique: item.parent ? serializer.toUnique(item.parent.path) : null,
			entityType: item.parent ? FORMS_EMAIL_TEMPLATE_FOLDER_ENTITY_TYPE : FORMS_EMAIL_TEMPLATE_ROOT_ENTITY_TYPE,
		},
		entityType: item.isFolder ? FORMS_EMAIL_TEMPLATE_FOLDER_ENTITY_TYPE : FORMS_EMAIL_TEMPLATE_ENTITY_TYPE,
		name: item.name,
		isFolder: item.isFolder,
		hasChildren: item.hasChildren,
		icon: item.isFolder ? undefined : 'icon-notepad',
	};
};
