import { FORMS_EMAIL_TEMPLATE_ROOT_ENTITY_TYPE } from '../entity.js';
import { FormsEmailTemplateTreeServerDataSource } from './email-template-tree.server.data-source.js';
import type { FormsEmailTemplateTreeItemModel, FormsEmailTemplateTreeRootModel } from './types.js';
import { FORMS_EMAIL_TEMPLATE_TREE_STORE_CONTEXT } from './email-template-tree.store.js';
import { UmbTreeRepositoryBase } from '@umbraco-cms/backoffice/tree';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import type { UmbApi } from '@umbraco-cms/backoffice/extension-api';

export class FormsEmailTemplateTreeRepository
	extends UmbTreeRepositoryBase<FormsEmailTemplateTreeItemModel, FormsEmailTemplateTreeRootModel>
	implements UmbApi
{
	constructor(host: UmbControllerHost) {
		super(host, FormsEmailTemplateTreeServerDataSource, FORMS_EMAIL_TEMPLATE_TREE_STORE_CONTEXT);
	}

	async requestTreeRoot() {
		const { data: treeRootData } = await this._treeSource.getRootItems({ skip: 0, take: 1 });
		const hasChildren = treeRootData ? treeRootData.total > 0 : false;

		const data: FormsEmailTemplateTreeRootModel = {
			unique: null,
			entityType: FORMS_EMAIL_TEMPLATE_ROOT_ENTITY_TYPE,
			name: 'Email Templates',
			hasChildren,
			isFolder: true,
		};

		return { data };
	}
}

export default FormsEmailTemplateTreeRepository;
